    .field.buy_me { padding-left: 0; padding-right: 0; }
    .buyme_error { display: none; padding: 5px 0; color: red; }
    .buy_me .buyme-image { height: 44px; width: 60px; border-radius: 5px 0 0 5px; }
    .buy_me .field__input-btn { display: flex; align-items: center; justify-content: center; cursor: pointer;}
    .buy_me .field__input-btn > div { width: 50%; }
    .field__input-btn { width: 120px !important; cursor: pointer; }
    .buyme_info { padding: 5px 0; text-decoration: underline; cursor: pointer !important; }
    .verify-popup.show button.btn{
      padding-block: 10px;
    }
    .verify-popup.show button.btn + button.btn{
      margin-right: 1rem;
    }
    .info-popup.show, .verify-popup.show {
      display: block;
    }
    .buyme-images-container{
      display: flex;
      gap: 1rem;
      margin-block: 1rem;
    }
    .info-popup, .verify-popup {
      display: none;
      position: fixed;
      background: #fff;
      text-align: center;
      border: 1px solid #000;
      top: 0;
      bottom: 0;
      left: 0;
      right: 0;
      margin: auto;
      padding: 50px 25px;
      z-index: 9999999;
      max-width: 45%;
      max-height: 25%;
      height: auto;
      overflow-y: auto;
    }
    .verify-popup{
      max-width: 20%;
      max-height: 10%;
      border-radius: 21px;
      border-color: #d9d9d9;
    }
    @media screen and (max-width: 767px) {
      .verify-popup{
        max-width: 70%;
        max-height: 15%;
        padding-block: 35px;
      }
    }
    .buyme-popup .close-icon {
      position: absolute;
      right: 0;
      top: -25px;
      cursor: pointer;
      width: 20px;
    }
    .buyme-popup .popup-title {
      margin-bottom: 25px;
      font-size: 1.5rem;
    }
    .popup-content {
      line-height: 1.4rem;
    }

    .verify-popup-wrapper{
      display: none;
    }
    .verify-loading{
      height: 100%;
      display: grid;
      place-items: 'center';
    }
    .verify-popup-balance{
      margin-block: 1.5rem;
      font-size: 1.5rem;
      color: black;
    }
