    from
    {
        -webkit-transform: rotate(0deg);
        -o-transform: rotate(0deg);
        transform: rotate(0deg);
    }

    to
    {
        -webkit-transform: rotate(360deg);
        -o-transform: rotate(360deg);
        transform: rotate(360deg);
    }
}

@keyframes rotating
{
    from
    {
        -ms-transform: rotate(0deg);
        -moz-transform: rotate(0deg);
        -webkit-transform: rotate(0deg);
        -o-transform: rotate(0deg);
        transform: rotate(0deg);
    }

    to
    {
        -ms-transform: rotate(360deg);
        -moz-transform: rotate(360deg);
        -webkit-transform: rotate(360deg);
        -o-transform: rotate(360deg);
        transform: rotate(360deg);
    }
}

.rotating
{
    -webkit-animation: rotating 2s linear infinite;
    -moz-animation: rotating 2s linear infinite;
    -ms-animation: rotating 2s linear infinite;
    -o-animation: rotating 2s linear infinite;
    animation: rotating 2s linear infinite;
}


@media only screen and (max-device-width:667px) {
    html.glassix-widget-open > body {
        height: 0 !important;
        margin: 0 !important;
        overflow: hidden !important;
    }

    #glassix-widget-iframe-container {
        top: 0 !important;
        left: 0 !important;
        right: 0 !important;
        bottom: 0 !important;
        border-radius: 0 !important;
        height: 100% !important;
        max-height: 100% !important;
        width: 100% !important;
    }

    .mobile-right #glassix-widget-iframe-container, .mobile-right #glassix-widget-launcher-container, .mobile-right #greeting-message-container
    {
        right: 30px;
        left: auto;
    }
    .mobile-left #glassix-widget-iframe-container, .mobile-left #glassix-widget-launcher-container, .mobile-left #greeting-message-container
    {
        left: 30px;
        right: auto;
    }
    .mobile-right #glassix-widget-launcher-badge
    {
        right: 0px;
    }
    .mobile-left #glassix-widget-launcher-badge
    {
        left: 0px;
    }
}
@media only screen and (max-device-width:350px) {
